public class BuilderPattern {
    static class Pizza {
        String size; boolean cheese, pepperoni;
        private Pizza() {}
        static class Builder {
            Pizza p = new Pizza();
            Builder size(String s) { p.size = s; return this; }
            Builder cheese() { p.cheese = true; return this; }
            Builder pepperoni() { p.pepperoni = true; return this; }
            Pizza build() { return p; }
        }
        @Override public String toString() {
            return size + ",ch=" + cheese + ",pep=" + pepperoni;
        }
    }
    public static void main(String[] args) {
        Pizza p = new Pizza.Builder().size("large").cheese().build();
        System.out.println(p);
    }
}
